import Foundation
import NaturalLanguage

print("NaturalLanguage Framework Demo\n")

// 1. Language Detection
print("1. Language Detection:")
let texts = [
    "Hello, how are you?",
    "Bonjour, comment allez-vous?",
    "Hola, como estas?",
    "Hallo, wie geht es dir?"
]

for text in texts {
    let recognizer = NLLanguageRecognizer()
    recognizer.processString(text)
    let lang = recognizer.dominantLanguage?.rawValue ?? "unknown"
    print("  '\(text.prefix(20))...' -> \(lang)")
}

// 2. Sentiment Analysis
print("\n2. Sentiment Analysis:")
let sentences = [
    "I love this product! It's absolutely amazing!",
    "This is terrible. I hate it so much.",
    "It's okay, nothing special."
]

for sentence in sentences {
    let tagger = NLTagger(tagSchemes: [.sentimentScore])
    tagger.string = sentence
    let (tag, _) = tagger.tag(at: tagger.string.startIndex, unit: .paragraph, scheme: .sentimentScore)
    let score = Double(tag?.rawValue ?? "0") ?? 0
    let sentiment = score > 0.2 ? "Positive" : (score < -0.2 ? "Negative" : "Neutral")
    print("  '\(sentence.prefix(30))...' -> \(sentiment) (\(String(format: "%.2f", score)))")
}

// 3. Tokenization
print("\n3. Tokenization:")
let text = "Swift is a powerful programming language."
let tokenizer = NLTokenizer(unit: .word)
tokenizer.string = text
let tokens = tokenizer.tokens(for: text.startIndex..<text.endIndex)
print("  Words: \(tokens.map { String(text[$0]) }.joined(separator: ", "))")
